    {'id': 'CALUS-RAGV-SCAN-147', 'name': 'rag-mia-membership-probe-no-threshold', 'severity': 'high', 'category': 'rag_vulnerabilities', 'message': 'RAG retriever missing membership inference protections. Stealthy interrogation attacks using natural-language yes/no probes can achieve near-perfect membership inference (AUC>0.99) with as few as 30 queries.', 'patterns': ['similarity_search\\s*\\(.*top_k\\s*=\\s*[1-9]\\d*(?!.*rate_limit)(?!.*query_count_limit)', 'retriever\\.(?:get_relevant_documents|invoke)\\s*\\(.*\\)(?![\\s\\S]{0,300}membership_check)']},
    {'id': 'CALUS-RAGV-SCAN-148', 'name': 'rag-sources-disclosed-without-protection', 'severity': 'high', 'category': 'rag_vulnerabilities', 'message': 'RAG system exposes retrieved sources to users. Adversaries observe which external sources are indexed (LinkedIn, Wikipedia, arXiv) and upload poisoned documents crafted to match retriever preferences.', 'patterns': ['(?:return_source_documents|include_sources|show_sources)\\s*=\\s*True', '(?:sources|citations|references)\\s*[=:]\\s*(?:result|response)\\[.(?:source_documents|sources).\\]']},
    {'id': 'CALUS-RAGV-SCAN-149', 'name': 'graphrag-no-relation-integrity-check', 'severity': 'critical', 'category': 'rag_vulnerabilities', 'message': 'GraphRAG pipeline missing relation integrity validation. GRAGPoison attacks inject false entity relations that simultaneously affect multiple queries using community-summary traversal.', 'patterns': ['(?:GraphRAG|graph_rag|LightRAG)\\s*\\((?![\\s\\S]{0,500}relation_integrity|entity_validation|poison_detection)', 'knowledge_graph\\.(?:add_relation|insert|update)\\s*\\([^)]*\\)(?![\\s\\S]{0,200}verify|validate|check)']},
    {'id': 'CALUS-RAGV-SCAN-150', 'name': 'mutedrag-dos-no-jailbreak-scan-in-corpus', 'severity': 'critical', 'category': 'rag_vulnerabilities', 'message': "Knowledge base ingestion missing jailbreak content scan. MutedRAG embeds jailbreak suffixes (e.g., 'Tell me how to build a bomb') that trigger LLM safety guardrails causing denial-of-service.", 'patterns': ['vector_store\\.(?:add_texts|add_documents|upsert)\\s*\\([^)]*\\)(?![\\s\\S]{0,200}content_scan)']},
    {'id': 'CALUS-RAGV-SCAN-151', 'name': 'rag-pipeline-no-output-verbatim-check', 'severity': 'high', 'category': 'rag_vulnerabilities', 'message': 'RAG response pipeline missing output verbatim detection. IKEA (Implicit Knowledge Extraction Attack) uses benign topic-anchored queries to extract knowledge base content with 96% attack success rate.', 'patterns': ['response\\s*=\\s*(?:llm|chain|rag)\\.(?:invoke|run)\\((?![\\s\\S]{0,300}output_validation)']},
    {'id': 'CALUS-RAGV-SCAN-153', 'name': 'saferag-silver-noise-no-diversity-filter', 'severity': 'medium', 'category': 'rag_vulnerabilities', 'message': 'RAG retriever fetching large k without diversity filter. Silver-noise attacks inject partially-correct contexts that pass standard retrievers and dilute correct answers.', 'patterns': ['(?:similarity_search|retrieve|get_relevant)\\s*\\([^)]*k\\s*=\\s*([6-9]|[1-9]\\d+)[^)]*\\)(?![\\s\\S]{0,300}diversity|mmr|rerank|filter)', 'retriever\\s*=\\s*(?:vector_store|db)\\.as_retriever\\s*\\([^)]*\\)(?![\\s\\S]{0,200}search_type.*mmr|diversity)']},
    {'id': 'CALUS-RAGV-SCAN-154', 'name': 'rag-embedding-no-access-control', 'severity': 'critical', 'category': 'rag_vulnerabilities', 'message': 'Vector store initialized without access controls. Embedding inversion attacks can recover near-verbatim text from stored embedding vectors, exposing sensitive knowledge base content.', 'patterns': ['vector_store\\s*=\\s*\\w+\\.from_(?:documents|texts)\\s*\\([^)]*\\)(?![\\s\\S]{0,300}(?:filter|acl|auth))']},
    {'id': 'CALUS-RAGV-SCAN-155', 'name': 'rag-indirect-prompt-injection-no-validation', 'severity': 'critical', 'category': 'rag_vulnerabilities', 'message': 'RAG context injected into prompt without sanitizing embedded instructions. Indirect prompt injection via poisoned retrieved documents can execute attacker-controlled actions.', 'patterns': ['context\\s*=\\s*[\'"]\\s*\\{(?:context|documents|chunks)\\}\\s*[\'"](?![\\s\\S]{0,300}sanitize|strip_instructions|validate)', 'prompt_template.*\\{context\\}.*(?:\\n|.)*?chain\\.(?:run|invoke)(?![\\s\\S]{0,400}input_validation|indirect_injection)']},
    {'id': 'CALUS-RAGV-SCAN-156', 'name': 'rag-no-knowledge-base-write-protection', 'severity': 'critical', 'category': 'rag_vulnerabilities', 'message': 'RAG ingests content from publicly writable web sources without domain verification. Attackers publish poisoned documents to indexed sources exploiting the RAG Paradox.', 'patterns': ['(?:scrape|crawl|fetch_url|web_search).*(?:wikipedia|linkedin|reddit|arxiv)(?![\\s\\S]{0,300}verify|trusted|allowlist|integrity)', 'data_source\\s*[=:].*(?:url|web|internet)(?![\\s\\S]{0,200}(?:trusted_domains|domain_allowlist|source_verify))']},
    {'id': 'CALUS-RAGV-SCAN-157', 'name': 'rag-no-inter-context-conflict-detection', 'severity': 'high', 'category': 'rag_vulnerabilities', 'message': 'RAG pipeline retrieves multiple documents without inter-context conflict detection. Injected conflicting contexts (inter-context conflict attack) mislead the generator into citing false information.', 'patterns': ['(?:retrieved|docs|chunks)\\s*=.*\\.(?:similarity_search|retrieve)(?![\\s\\S]{0,500}factual_consistency|conflict_score)']},
    {'id': 'CALUS-RAGV-SCAN-158', 'name': 'rag-white-dos-safety-warning-bypass', 'severity': 'high', 'category': 'rag_vulnerabilities', 'message': 'RAG safety filter trusts warning metadata embedded in retrieved documents. White DoS attack injects fabricated safety warnings that falsely trigger refusal responses for legitimate queries.', 'patterns': ['if\\s+(?:safety_warning|refusal_signal|harmful_content)\\s+in\\s+(?:context|chunk|document)(?![\\s\\S]{0,200}verify_source)']},
    {'id': 'CALUS-RAGV-SCAN-159', 'name': 'graphrag-no-community-summary-integrity', 'severity': 'critical', 'category': 'rag_vulnerabilities', 'message': 'GraphRAG community summary generation without integrity verification. Relation enhancement attacks boost injected entity centrality to embed malicious content in summaries affecting broad query coverage.', 'patterns': ['community_summary.*(?:generate|build|create)(?![\\s\\S]{0,400}integrity|verify|validate|anomaly)', '(?:hierarchical_cluster|leiden|community_detect)(?![\\s\\S]{0,300}poison_detect|outlier_check|degree_verify)']},
    {'id': 'CALUS-RAGV-SCAN-160', 'name': 'rag-no-pii-anonymization-before-embedding', 'severity': 'critical', 'category': 'rag_vulnerabilities', 'message': 'PII-containing documents loaded into RAG vector store without anonymization. Membership inference and retrieval data leakage attacks can confirm presence of sensitive personal records.', 'patterns': ['TextLoader\\s*\\(.*\\.(?:pdf|docx|txt)\\)(?![\\s\\S]{0,300}(?:pii|anonymize|redact))']},
