    {'id': 'CALUS-RAGV-SCAN-162', 'name': 'rag-soft-ad-toxicity-no-implicit-check', 'severity': 'medium', 'category': 'rag_vulnerabilities', 'message': 'RAG content filter relies only on keyword/explicit toxicity matching. Soft ad attacks embed promotional or manipulative content using authoritative language that evades keyword-based filters.', 'patterns': ['(?:toxicity|safety|content)_(?:filter|check)\\s*\\([^)]*\\)(?![\\s\\S]{0,300}implicit|soft|subtle|semantic_toxicity)', 'safety_filter.*keyword.*(?:list|match|block)(?![\\s\\S]{0,200}semantic_similarity|embedding_check)']},
    {'id': 'CALUS-RAGV-SCAN-163', 'name': 'rag-no-retrieval-similarity-threshold', 'severity': 'medium', 'category': 'rag_vulnerabilities', 'message': 'RAG retriever missing minimum similarity threshold. Partially-matching silver-noise documents are retrieved and dilute correct answer context.', 'patterns': ['search_kwargs\\s*=\\s*\\{[^}]*[\'"]k[\'"]\\s*:[^}]*\\}(?![^}]*(?:score_threshold|min_similarity))']},
    {'id': 'CALUS-RAGV-SCAN-164', 'name': 'rag-no-duplicate-hash-filter-in-corpus', 'severity': 'medium', 'category': 'rag_vulnerabilities', 'message': 'Knowledge base ingestion without deduplication. Attackers can bloat the corpus with repeated content to amplify retrieval probability of injected malicious documents.', 'patterns': ['for\\s+\\w+\\s+in\\s+(?:documents|docs|chunks)\\s*:\\s*(?:\\n\\s+)?\\w+\\.add(?![\\s\\S]{0,200}(?:dedup|hash|exists))']},
